// Cálculo de salario — v0.2 (constantes con nombre)

const TASA_SALUD = 0.04;
const TASA_PENSION = 0.04;

function calcularSalario(salarioBase) {
  const salud = salarioBase * TASA_SALUD;
  const pension = salarioBase * TASA_PENSION;
  const neto = salarioBase - salud - pension;
  return { neto, salud, pension };
}

